function formClass(f){
    return f==='voice_memo'?'voice':f==='counseling'?'counsel':f==='time_capsule'?'capsule':f==='diary'?'diary':'voice'
}

function formIcon(f){
    return f==='voice_memo'?'🎙':f==='counseling'?'🛋':f==='time_capsule'?'💌':f==='diary'?'📔':'📖'
}

function formLabel(f){
    return f==='voice_memo'?'查看语音':f==='counseling'?'查看咨询':f==='time_capsule'?'查看胶囊':f==='diary'?'查看日记':'查看语音'
}

