function voiceMemoPage(e,d){
    if(!d||d._raw){
        return "<div class='ms-output-page'>"+
            "<div class='ms-dark ms-voice ms-dark-scroll'>"+
                "<div class='ms-dark-nav'>"+
                    "<button class='ms-dark-back' data-ms-act='open-event' data-id='"+esc(e.id)+"'>← 返回</button>"+
                    "<span class='ms-dark-label'>语音备忘录</span>"+
                "</div>"+
                genCard(e,'voice_memo','语音备忘录')+
            "</div>"+
        "</div>"
    }

    var html="<div class='ms-output-page'>"+
        "<div class='ms-dark ms-voice ms-dark-scroll'>"+
            "<div class='ms-dark-nav'>"+
                "<button class='ms-dark-back' data-ms-act='open-event' data-id='"+esc(e.id)+"'>← 返回</button>"+
                "<span class='ms-dark-label'>语音备忘录</span>"+
            "</div>";

    html+='<div class="ms-voice-header">'+
        '<div class="ms-voice-event">'+esc(e.title)+'</div>'+
        '<div class="ms-voice-range">'+esc(e.startL)+'L - '+esc(e.endL)+'L</div>'+
    '</div>';

    html+=voiceMemoList(d);
    html+='</div></div>';

    return html
}

function voiceMemoList(text){
    var html='<div class="ms-voice-list">';
    var lines=String(text||'').split('\n');
    var current=null;

    lines.forEach(function(line){
        line=line.trim();
        if(!line){
            if(current){
                html+='</div></div>';
                current=null
            }
            return
        }

        if(line.match(/^(新录音|录音|凌晨|不知道第几条|删掉的那条)/)||line.match(/^\d+:\d+$/)){
            if(current){
                html+='</div></div>'
            }
            current=true;
            html+='<div class="ms-voice-item" data-ms-act="toggle-voice-item">';
            html+='<div class="ms-voice-row">';
            html+='<div class="ms-voice-play"><svg viewBox="0 0 24 24" width="14" height="14"><polygon points="8,5 19,12 8,19" fill="currentColor"/></svg></div>';
            html+='<div class="ms-voice-info"><div class="ms-voice-name">'+esc(line)+'</div></div>';
            html+='</div>';
            html+='<div class="ms-voice-transcript">'
        }else{
            var cls='ms-t-line';
            if(line.indexOf('……')>=0)cls+=' ms-t-hesitate';
            if(line.indexOf('[')>=0&&line.indexOf(']')>=0)cls+=' ms-t-env';
            if(line==='……')cls='ms-t-silence';
            html+='<div class="'+cls+'">'+esc(line)+'</div>'
        }
    });

    if(current){
        html+='</div></div>'
    }

    html+='</div>';
    return html
}

