function formatCounselText(text){
    var html='';
    var lines=String(text||'').split('\n');
    var section='';
    var inDialogue=false;
    var speaker='';

    lines.forEach(function(line){
        line=line.trim();
        if(!line)return;

        if(line.indexOf('[第一篇')>=0||line.indexOf('第一篇')>=0){
            html+='<div class="ms-counsel-section"><div class="ms-counsel-sec-title">初诊陈述</div>';
            section='first';
            return
        }
        if(line.indexOf('[第二篇')>=0||line.indexOf('第二篇')>=0){
            if(inDialogue)html+='</div>';
            html+='</div><div class="ms-counsel-section"><div class="ms-counsel-sec-title">深入剖析</div>';
            section='second';
            inDialogue=false;
            return
        }
        if(line.indexOf('[第三篇')>=0||line.indexOf('第三篇')>=0||line.indexOf('咨询师手记')>=0){
            if(inDialogue)html+='</div>';
            html+='</div><div class="ms-counsel-section"><div class="ms-counsel-sec-title">咨询师手记</div>';
            section='third';
            inDialogue=false;
            return
        }

        if(line.indexOf('来访者：')===0||line.indexOf('来访者:')===0){
            if(inDialogue)html+='</div>';
            html+='<div class="ms-counsel-dlg ms-spk-client">';
            html+='<div class="ms-counsel-speaker">来访者</div>';
            html+='<div class="ms-counsel-dlg-text">'+esc(line.replace(/^来访者[：:]/,''))+'</div>';
            html+='</div>';
            return
        }
        if(line.indexOf('咨询师：')===0||line.indexOf('咨询师:')===0){
            if(inDialogue)html+='</div>';
            html+='<div class="ms-counsel-dlg ms-spk-therapist">';
            html+='<div class="ms-counsel-speaker">咨询师</div>';
            html+='<div class="ms-counsel-dlg-text">'+esc(line.replace(/^咨询师[：:]/,''))+'</div>';
            html+='</div>';
            return
        }

        if(line.indexOf('——')>=0&&line.indexOf('沉默')>=0){
            html+='<div class="ms-counsel-pause">'+esc(line)+'</div>';
            return
        }

        html+='<div class="ms-counsel-narrative">'+esc(line)+'</div>'
    });

    if(inDialogue)html+='</div>';
    if(section)html+='</div>';

    return html
}

