function formatCapsuleText(text){
    var html='';
    var lines=String(text||'').split('\n');

    lines.forEach(function(line){
        line=line.trim();
        if(!line)return;

        var cls='ms-tc-line';
        if(line.indexOf('写于')>=0||line.indexOf('落款')>=0){
            html+='<div class="ms-tc-sign"><div class="ms-tc-sign-from">'+esc(line)+'</div><div class="ms-tc-sign-stamp">已封存</div></div>';
            return
        }
        if(line.indexOf('……')>=0)cls+=' ms-tc-hesitate';
        if(line.match(/^[A-Za-z]/))cls+=' ms-tc-dim';

        html+='<div class="'+cls+'">'+esc(line)+'</div>'
    });

    return html
}

