function formatDiaryText(text){
    var html='';
    var entries=String(text||'').split(/\n\n+/);
    var months=['一月','二月','三月','四月','五月','六月','七月','八月','九月','十月','十一月','十二月'];

    entries.forEach(function(entry){
        if(!entry.trim())return;

        html+='<div class="ms-diary-entry">';
        html+='<div class="ms-de-header">';

        var lines=entry.split('\n');
        var dateLine=lines[0]||'';
        html+='<div class="ms-de-date">'+esc(dateLine)+'</div>';

        if(lines.length>1&&lines[1].match(/周|天气|晴|雨|阴/)){
            html+='<div class="ms-de-day">'+esc(lines[1])+'</div>';
            lines.splice(0,2)
        }else{
            lines.splice(0,1)
        }

        html+='</div>';
        html+='<div class="ms-de-body">';

        lines.forEach(function(line){
            line=line.trim();
            if(!line)return;

            var cls='ms-de-para';
            if(line.indexOf('划掉')>=0||line.indexOf('~~')>=0)cls+=' ms-de-scratch';
            if(line.match(/^[A-Za-z]/))cls+=' ms-de-faint';

            html+='<div class="'+cls+'">'+esc(line)+'</div>'
        });

        html+='</div>';
        html+='<div class="ms-de-footer"><span></span><span></span></div>';
        html+='</div>'
    });

    return html
}

