function renderMemory(s){
    var view=s.ui.memoryView||'list';
    var ev=active(s.events).find(function(x){return x.id===s.ui.currentEventId});

    var html="<div class='ms-page'>"+
        eventList(s,view!=='list');

    if(view==='detail'&&ev){
        html+=detailPage(s,ev)
    }

    if(view==='output'&&ev){
        var type=ev.content_type||s.ui.currentOutputType||'voice_memo';
        var d=(ev.outputs&&ev.outputs[type])||null;

        if(type==='counseling'){
            html+=counselingPage(ev,d)
        }else if(type==='time_capsule'){
            html+=timeCapsulePage(ev,d)
        }else if(type==='diary'){
            html+=diaryPage(ev,d)
        }else{
            html+=voiceMemoPage(ev,d)
        }
    }

    html+="</div>";
    return html
}

function milestones(s){
    var evs=active(s.events);
    var ids={};
    evs.forEach(function(e){ids[e.id]=true});

    var ms=active(s.milestones).filter(function(m){
        return !m.event_id||ids[m.event_id]
    });

    if(ms.length)return ms;

    return evs.slice(0,8).map(function(e){
        return{
            id:'evms_'+e.id,
            event_id:e.id,
            title:e.title,
            L:e.endL||e.startL||0,
            month:(e.time_label||'').split('·')[0]||'四月',
            importance:e.weight||4,
            char_comment:e.quote||'',
            dialogue:[]
        }
    })
}

function renderStarmap(s){
    var ms=milestones(s);
    var pos=[
        {l:18,t:35},{l:35,t:20},{l:50,t:45},{l:65,t:28},
        {l:80,t:50},{l:25,t:58},{l:58,t:18},{l:74,t:38}
    ];

    var stars=ms.slice(0,8).map(function(m,i){
        var p=pos[i]||{l:20+i*7,t:30+i*5};
        var sz=m.importance>=5?'s5':m.importance>=4?'s4':m.importance>=3?'s3':'s2';

        return "<div class='sm-star "+sz+"' style='left:"+p.l+"%;top:"+p.t+"%' data-star-id='"+esc(m.id)+"'>"+
            "<div class='sm-star-label'>"+esc(clip(m.title,18))+"</div>"+
            "<div class='sm-star-core'></div>"+
        "</div>"
    }).join('');

    var labels=[];
    ms.forEach(function(m){
        if(m.month&&labels.indexOf(m.month)<0)labels.push(m.month)
    });
    if(!labels.length)labels=['三月','四月初','四月中','四月末'];
    while(labels.length<4)labels.push('');

    return "<div class='sm-page'>"+
        "<div class='sm-head'>"+
            "<div class='sm-head-bar'>"+
                "<div class='sm-head-left'>"+
                    "<button class='sm-back-btn' data-lp-nav='hero'>←</button>"+
                    "<span class='sm-title'>记忆星图</span>"+
                "</div>"+
                "<span class='sm-count'>"+ms.length+" 个时刻</span>"+
            "</div>"+
        "</div>"+
        "<div class='sm-starmap'>"+
            "<div class='sm-bg-gradient'></div>"+
            "<div class='sm-bg-grid'></div>"+
            "<div class='sm-bg-stars' id='sm-bg-stars'></div>"+
            "<svg class='sm-constellation-svg' id='sm-constellation' viewBox='0 0 375 812'></svg>"+
            stars+
            "<div class='sm-timeline-axis'></div>"+
            "<div class='sm-timeline-labels'>"+
                labels.slice(0,4).map(function(x){
                    return "<span class='sm-timeline-label'>"+esc(x)+"</span>"
                }).join('')+
            "</div>"+
            "<div class='sm-bottom-hint'>点击星星查看那个时刻</div>"+
            "<div class='sm-star-detail' id='sm-star-detail'>"+
                "<div class='sm-star-detail-mask' data-ms-act='close-star'></div>"+
                "<div class='sm-star-detail-panel'>"+
                    "<div class='sm-panel-head'>"+
                        "<div>"+
                            "<div class='sm-panel-title' id='sm-panel-title'></div>"+
                            "<div class='sm-panel-sub' id='sm-panel-sub'></div>"+
                        "</div>"+
                        "<button class='sm-panel-close' data-ms-act='close-star'>✕</button>"+
                    "</div>"+
                    "<div class='sm-panel-body' id='sm-panel-body'></div>"+
                "</div>"+
            "</div>"+
        "</div>"+
    "</div>"
}

