function afterRender(s){
    try{
        ensureStyle();
    }catch(e){
        console.warn('[MemoryStarmap style]',e)
    }

    var root=base().ensureRoot?base().ensureRoot():q('#'+ROOT_ID);

    var bg=q('#sm-bg-stars',root);
    if(bg&&!bg.getAttribute('data-done')){
        bg.setAttribute('data-done','1');
        var h='';
        for(var i=0;i<120;i++){
            var x=Math.random()*100;
            var y=Math.random()*100;
            var sz=Math.random()<.1?3:(Math.random()<.3?2:1);
            var o1=(.1+Math.random()*.3).toFixed(2);
            var o2=(.5+Math.random()*.5).toFixed(2);
            var dur=(2+Math.random()*4).toFixed(1);
            var del=(Math.random()*5).toFixed(1);
            h+="<div class='sm-bg-star' style='left:"+x+"%;top:"+y+"%;width:"+sz+"px;height:"+sz+"px;--o1:"+o1+";--o2:"+o2+";--dur:"+dur+"s;animation-delay:"+del+"s'></div>"
        }
        bg.innerHTML=h
    }

    var svg=q('#sm-constellation',root);
    if(svg){
        var arr=qa('.sm-star',root).map(function(el){
            return{
                x:(parseFloat(el.style.left)||0)/100*375,
                y:(parseFloat(el.style.top)||0)/100*812
            }
        });
        var lines='';
        for(var j=0;j<arr.length-1;j++){
            lines+="<line class='sm-const-line' x1='"+arr[j].x+"' y1='"+arr[j].y+"' x2='"+arr[j+1].x+"' y2='"+arr[j+1].y+"'/>"
        }
        svg.innerHTML=lines
    }

    qa('[data-star-id]',root).forEach(function(el){
        if(el.getAttribute('data-star-bound')==='1')return;
        el.setAttribute('data-star-bound','1');
        el.onclick=function(e){
            e.stopPropagation();
            openStar(s,this.getAttribute('data-star-id'))
        }
    })
}

function openStar(s,id){
    var ms=milestones(s);
    var m=ms.find(function(x){return String(x.id)===String(id)});
    if(!m)return;

    var root=base().ensureRoot?base().ensureRoot():q('#'+ROOT_ID);
    var box=q('#sm-star-detail',root);
    var ti=q('#sm-panel-title',root);
    var su=q('#sm-panel-sub',root);
    var bo=q('#sm-panel-body',root);

    if(!box||!ti||!su||!bo)return;

    ti.textContent=m.title||'未命名时刻';
    su.textContent=(m.L||0)+'L · '+(m.month||'')+' · 重要性 '+(m.importance||3);

    var html='';
    if(m.char_comment){
        html+="<div class='sm-panel-quote'>"+esc(m.char_comment)+"</div>"
    }

    if(m.dialogue&&m.dialogue.length){
        html+="<div style='margin:14px 0 8px;font-size:10px;font-weight:900;letter-spacing:.08em;text-transform:uppercase;color:rgba(255,255,255,.2)'>原文片段</div>";
        m.dialogue.forEach(function(line){
            html+="<div style='margin-bottom:8px;font-size:13px;line-height:1.7'>"+
                "<span style='color:rgba(255,200,120,.5);font-weight:800;font-size:11px'>"+esc(line.speaker||'')+"</span>"+
                "<span style='color:rgba(255,255,255,.3);margin:0 6px'>·</span>"+
                "<span style='color:rgba(255,255,255,.6)'>"+esc(line.text||'')+"</span>"+
            "</div>"
        })
    }

    var ev=active(s.events).find(function(e){
        return e.id===m.event_id||e.title===m.title
    });
    if(ev){
        html+="<button class='sm-panel-enter' data-ms-act='open-event' data-id='"+esc(ev.id)+"'>查看完整甜蜜回忆 →</button>"
    }

    bo.innerHTML=html||"<div class='sm-panel-quote'>暂无详情。</div>";
    box.classList.add('open')
}

async function act(a,n,s){
    var c=core();
    s=s||await c.load();

    if(a==='open-event'){
        s.ui.page='memory';
        s.ui.memoryView='detail';
        s.ui.currentEventId=n.getAttribute('data-id');
        await c.save(s);
        return true
    }

    if(a==='back-list'){
        s.ui.memoryView='list';
        s.ui.currentEventId='';
        await c.save(s);
        return true
    }

    if(a==='open-output'){
        s.ui.page='memory';
        s.ui.memoryView='output';
        s.ui.currentEventId=n.getAttribute('data-id');
        s.ui.currentOutputType=n.getAttribute('data-type')||'voice_memo';
        await c.save(s);
        return true
    }

    if(a==='generate-output'){
        var id=n.getAttribute('data-id');
        var type=n.getAttribute('data-type')||'voice_memo';
        if(base().toast)base().toast('生成中...');

        await c.generateOutput(id,type);
        s=await c.load();
        s.ui.page='memory';
        s.ui.memoryView='output';
        s.ui.currentEventId=id;
        s.ui.currentOutputType=type;
        await c.save(s);
        return true
    }

    if(a==='open-capsule'){
        var root=base().ensureRoot?base().ensureRoot():q('#'+ROOT_ID);
        var letter=q('#ms-capsule-letter',root);
        var cover=n.closest('.ms-capsule-cover');
        if(letter)letter.classList.add('open');
        if(cover)cover.style.display='none';
        return true
    }

    if(a==='close-star'){
        var root2=base().ensureRoot?base().ensureRoot():q('#'+ROOT_ID);
        var d=q('#sm-star-detail',root2);
        if(d)d.classList.remove('open');
        return true
    }

    if(a==='reroll-event'){
        if(!c.rerollEvent){base().toast&&base().toast('核心模块版本过旧');return true}
        if(!confirm('确认重抽这条甜蜜回忆？旧的展示内容会被清空。'))return true;
        await c.rerollEvent(n.getAttribute('data-id'));
        return true
    }

    if(a==='edit-event'){
        editEventOverlay(s,n.getAttribute('data-id'));
        return true
    }

    if(a==='save-event-edit'){
        if(!c.updateEvent){base().toast&&base().toast('核心模块版本过旧');return true}

        var pts=[];
        try{pts=JSON.parse(q('#ms-edit-points').value||'[]')}catch(e){
            base().toast&&base().toast('记忆点 JSON 格式错误');
            return true
        }
        if(!Array.isArray(pts)){base().toast&&base().toast('记忆点必须是数组');return true}

        await c.updateEvent(n.getAttribute('data-id'),{
            title:q('#ms-edit-title').value,
            time_label:q('#ms-edit-time').value,
            weight:q('#ms-edit-weight').value,
            content_type:q('#ms-edit-form').value,
            tags:q('#ms-edit-tags').value,
            quote:q('#ms-edit-quote').value
        },pts);

        base().closeOverlay&&base().closeOverlay();
        return true
    }

    if(a==='delete-event'){
        if(!c.deleteEvent){base().toast&&base().toast('核心模块版本过旧');return true}
        if(!confirm('确认删除这条甜蜜回忆？'))return true;
        await c.deleteEvent(n.getAttribute('data-id'));
        return true
    }

    if(a==='toggle-voice-item'){
        n.classList.toggle('open');
        return true
    }

    return false
}

